CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  email VARCHAR(255) UNIQUE NOT NULL,
  created_at TIMESTAMP DEFAULT NOW()
);

CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  user_id INTEGER REFERENCES users(id),
  total DECIMAL(10,2) NOT NULL,
  status VARCHAR(20) DEFAULT 'pending'
);

CREATE INDEX idx_users_email ON users(email);

-- Get users with their orders (INNER JOIN)
SELECT u.name, o.total, o.status
FROM users u
JOIN orders o ON o.user_id = u.id
WHERE u.id = 1;

-- Transaction: transfer money
BEGIN;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;
-- If anything fails before COMMIT, ROLLBACK undoes everything

-- SQL: structured, relational
INSERT INTO users (name, email) VALUES ('Alice', 'alice@example.com');
SELECT * FROM users WHERE email = 'alice@example.com';

// NoSQL (MongoDB): flexible, document-based
db.users.insertOne({ name: 'Alice', email: 'alice@example.com', tags: ['dev', 'admin'] });
db.users.find({ email: 'alice@example.com' });
